={{(() => {
  if ($json.__prefs) return $json.__prefs.ingredients || '';

  const buildPrefs = () => {
    if ($json.ingredients || $json.cuisine_preference || $json.max_time_minutes) {
      const directMax = Number($json.max_time_minutes);
      return {
        ingredients: $json.ingredients || '',
        cuisine_preference: $json.cuisine_preference || 'any',
        max_time_minutes: Number.isFinite(directMax) ? directMax : null,
        parse_error: ''
      };
    }

    const msg = $json?.choices?.[0]?.message?.content?.[0]?.text ?? $json?.data?.[0]?.content?.[0]?.text ?? $json?.text ?? $json?.message ?? '';
    let parsed = {};

    try {
      parsed = typeof msg === 'string' && msg.trim()
        ? JSON.parse(msg)
        : (typeof msg === 'object' && msg !== null ? msg : {});
    } catch (error) {
      parsed = { parse_error: error.message };
    }

    const parsedMax = Number(parsed.max_time_minutes);

    return {
      ingredients: parsed.ingredients || '',
      cuisine_preference: parsed.cuisine_preference || 'any',
      max_time_minutes: Number.isFinite(parsedMax) ? parsedMax : null,
      parse_error: parsed.parse_error || ''
    };
  };

  $json.__prefs = buildPrefs();
  return $json.__prefs.ingredients;
})()}}

