// Format the first recipe result coming from Edamam
const itemsIn = Array.isArray(items) ? items : [];
const first = (itemsIn[0] || {}).json || {};
const hits = Array.isArray(first.hits) ? first.hits : [];

if (!hits.length || !hits[0].recipe) {
  return [{
    json: {
      title: 'No recipes found',
      imageUrl: '',
      recipeUrl: '',
      calories: 0,
      ingredientCount: 0,
      note: 'No recipes matched your request. Try different ingredients or tweak cuisine/time preferences.'
    }
  }];
}

const recipe = hits[0].recipe;

return [{
  json: {
    title: recipe.label || 'Recipe',
    imageUrl: recipe.image || '',
    recipeUrl: recipe.url || '',
    calories: Math.round(recipe.calories || 0),
    ingredientCount: Array.isArray(recipe.ingredientLines) ? recipe.ingredientLines.length : 0
  }
}];
